# Helper functions

def get_next_id(items, key):
    if not items:
        return 1
    return max(item[key] for item in items) + 1


def find_book_by_id(book_id):
    books = read_books()
    for book in books:
        if book['book_id'] == book_id:
            return book
    return None


def find_category_by_id(category_id):
    categories = read_categories()
    for cat in categories:
        if cat['category_id'] == category_id:
            return cat
    return None


def compute_cart_total(cart_items):
    total = 0.0
    books = {book['book_id']: book for book in read_books()}
    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            total += book['price'] * item['quantity']
    return total


def filter_books_by_search_category(books, search_term, category_name):
    filtered = books
    if search_term:
        search_term_lower = search_term.lower()
        filtered = [b for b in filtered if search_term_lower in b['title'].lower() or search_term_lower in b['author'].lower()]
    if category_name and category_name.lower() != 'all':
        filtered = [b for b in filtered if b['category'].lower() == category_name.lower()]
    return filtered

