    try:
        book_id_int = int(book_id)
    except:
        abort(404)

    book = find_book_by_id(book_id_int)
    if not book:
        abort(404)

    reviews_all = read_reviews()
    # filter reviews for this book
    reviews = [r for r in reviews_all if r['book_id'] == book_id_int]

    if request.method == 'POST':
        # Handle add to cart
        cart_items = read_cart()
        # check if book already in cart
        existing = None
        for item in cart_items:
            if item['book_id'] == book_id_int:
                existing = item
                break
        if existing:
            existing['quantity'] += 1
        else:
            new_cart_id = get_next_id(cart_items, 'cart_id')
            today_str = datetime.today().strftime('%Y-%m-%d')
            cart_items.append({
                'cart_id': new_cart_id,
