                'quantity': 1,
                'added_date': today_str
            })
        save_cart(cart_items)
        return redirect(url_for('book_details_page', book_id=book_id))

    elif request.method == 'DELETE':
        # Remove book from cart regardless of quantity
        cart_items = read_cart()
        cart_items = [item for item in cart_items if item['book_id'] != book_id_int]
        save_cart(cart_items)
        return ('', 204)

    else:  # GET
