    book_reviews = [r for r in reviews_all if r['book_id'] == book_id_int]

    if request.method == 'DELETE':
        # Remove book from cart.txt regardless of quantity
        cart_items = read_cart()
        cart_items = [item for item in cart_items if item['book_id'] != book_id_int]
        save_cart(cart_items)
        return ('', 204)

    # GET
    return render_template('book_details.html', book=book, reviews=book_reviews)

@app.route('/cart', methods=['GET', 'PUT'])
def cart_page():
    cart_items = read_cart()

    if request.method == 'PUT':
        form_data = request.form
        to_remove_ids = set()
        updated_quantities = {}

        for key in form_data:
            if key.startswith('update-quantity-'):
                try:
                    cart_id = int(key[len('update-quantity-'):])
                    quantity = int(form_data[key])
                    if quantity < 1:
                        to_remove_ids.add(cart_id)
                    else:
                        updated_quantities[cart_id] = quantity
                except:
                    continue
            elif key.startswith('remove-item-button-'):
                try:
                    cart_id = int(key[len('remove-item-button-'):])
                    to_remove_ids.add(cart_id)
                except:
                    continue

        cart_items = [item for item in cart_items if item['cart_id'] not in to_remove_ids]
        for item in cart_items:
            if item['cart_id'] in updated_quantities:
                item['quantity'] = updated_quantities[item['cart_id']]

        save_cart(cart_items)

    cart_display = cart_with_books(cart_items)
    total_amount = calculate_total(cart_display)

    return render_template('cart.html', cart_items=cart_display, total_amount=total_amount)

@app.route('/checkout', methods=['GET', 'DELETE'])
def checkout_page():
    cart_items = read_cart()
    cart_display = cart_with_books(cart_items)

    status_filter = 'All'  # As mentioned in the spec
    order_items = read_order_items()  # For context variable in checkout - spec unclear on usage, but we pass empty list
    rating_filter = 'All'  # Spec mentions ratingfilter str but no clear processing here

    if request.method == 'DELETE':
        # Spec did not clarify what DELETE on checkout should do exactly
        # We respond with 204 No Content
        return ('', 204)

    # GET
    return render_template('checkout.html', cart_items=cart_display, statusfilter=status_filter, orderitems=order_items, ratingfilter=rating_filter)

@app.route('/write-review', methods=['GET', 'PATCH'])
def write_review_page():
    books = read_books()
    books_purchased = books  # Spec does not define filtering

    time_period = 'All Times'  # For context variable

    if request.method == 'PATCH':
        # Receive form data: book_id (str), rating (str), review_text (str)
        data = request.form
        book_id_raw = data.get('book_id')
        rating_raw = data.get('rating')
        review_text = data.get('review_text', '').strip()

        try:
            book_id = int(book_id_raw)
            rating = int(rating_raw)
            if rating < 1 or rating > 5 or not review_text:
                raise ValueError
        except:
            # Re-render on error
            return render_template('write_review.html', books_purchased=books_purchased, timeperiod=time_period)

        reviews = read_reviews()
        new_review_id = get_next_id(reviews, 'review_id')
        date_str = datetime.today().strftime('%Y-%m-%d')
        # We do not have customer name from form, so leave empty or use "Anonymous"
        new_review = {
            'review_id': new_review_id,
            'book_id': book_id,
            'customer_name': 'Anonymous',
            'rating': rating,
            'review_text': review_text,
            'review_date': date_str
        }
        reviews.append(new_review)
        save_reviews(reviews)

        # After successful patch, redirect to /reviews page
        return redirect(url_for('reviews_page'))

    # GET
    return render_template('write_review.html', books_purchased=books_purchased, timeperiod=time_period)

@app.route('/bestsellers', methods=['GET'])
def bestsellers_page():
    time_period = request.args.get('time_period', 'This Month')
    bestsellers_all = read_bestsellers()

    filtered = [b for b in bestsellers_all if b['period'] == time_period]
    books_map = {b['book_id']: b for b in read_books()}

    bestsellers = []
    for b in filtered:
        book = books_map.get(b['book_id'])
        if book:
            bestsellers.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'author': book['author'],
                'sales': b['sales_count']
            })

    return render_template('bestsellers.html', bestsellers=bestsellers, time_period=time_period)


