# Helpers

def get_next_id(lst, key):
    if not lst:
        return 1
    return max(item[key] for item in lst) + 1

def find_book_by_id(book_id):
    books = read_books()
    for b in books:
        if b['book_id'] == book_id:
            return b
    return None

def find_category_by_id(category_id):
    categories = read_categories()
    for c in categories:
        if c['category_id'] == category_id:
            return c
    return None

def filter_books(books, search_term, category_filter):
    filtered = books
    if search_term:
        term = str(search_term).lower()
        filtered = [b for b in filtered if term in b['title'].lower() or term in b['author'].lower()]
    if category_filter and category_filter.lower() != 'all':
        filtered = [b for b in filtered if b['category'].lower() == category_filter.lower()]
    return filtered


def prepare_cart_items_with_books(cart_items):
    books = {b['book_id']: b for b in read_books()}
    results = []
    for item in cart_items:
        book = books.get(item['book_id'])
        if book:
            subtotal = book['price'] * item['quantity']
            results.append({
                'cart_id': item['cart_id'],
                'book': book,
                'quantity': item['quantity'],
                'price': book['price'],
                'subtotal': subtotal
            })
    return results

def calculate_cart_total(cart_items_with_books):
    total = 0.0
    for item in cart_items_with_books:
        total += item['subtotal']
    return total


