@app.route('/cart', methods=['GET', 'PUT'])
def cart_page():
    cart_items = read_cart()
    if request.method == 'PUT':
        form_data = request.form
        to_remove_ids = set()
        update_quantities = {}

        for key in form_data.keys():
            if key.startswith('update-quantity-'):
                try:
                    cart_id = int(key[len('update-quantity-'):])
                    quantity = int(form_data[key])
                    if quantity < 1:
                        to_remove_ids.add(cart_id)
                    else:
                        update_quantities[cart_id] = quantity
                except:
                    continue
            elif key.startswith('remove-item-button-'):
                try:
                    cart_id = int(key[len('remove-item-button-'):])
                    to_remove_ids.add(cart_id)
                except:
                    continue

        cart_items = [item for item in cart_items if item['cart_id'] not in to_remove_ids]
        for item in cart_items:
            if item['cart_id'] in update_quantities:
                item['quantity'] = update_quantities[item['cart_id']]

        save_cart(cart_items)

    cart_display = prepare_cart_items_with_books(cart_items)
    total_amount = calculate_cart_total(cart_display)

    return render_template('cart.html', cart_items=cart_display, total_amount=total_amount)

