        # Spec unclear on exact purpose, so just return empty response
        return ('', 204)

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or not payment_method:
            # Invalid submission, just re-render
            return render_template('checkout.html', cart_items=cart_display, statusfilter=statusfilter, orderitems=orderitems, ratingfilter=ratingfilter)

        orders = read_orders()
        orderitems_all = read_order_items()

        new_order_id = get_next_id(orders, 'order_id')
        today = datetime.today().strftime('%Y-%m-%d')
        total_amount = calculate_cart_total(cart_display)

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }

        orders.append(new_order)
        save_orders(orders)

        current_order_item_id = get_next_id(orderitems_all, 'order_item_id')
        for item in cart_items:
            order_item = {
                'order_item_id': current_order_item_id,
                'order_id': new_order_id,
