@app.route('/cart', methods=['GET', 'PUT'])
def cart_page():
    cart_items = read_cart()
    if request.method == 'PUT':
        form_data = request.form
        to_remove_ids = set()
        update_quantities = {}

        for key in form_data.keys():
            if key.startswith('update-quantity-'):
                try:
                    cart_id = int(key[len('update-quantity-'):])
                    quantity = int(form_data[key])
                    if quantity < 1:
                        to_remove_ids.add(cart_id)
                    else:
                        update_quantities[cart_id] = quantity
                except:
                    continue
            elif key.startswith('remove-item-button-'):
                try:
                    cart_id = int(key[len('remove-item-button-'):])
                    to_remove_ids.add(cart_id)
                except:
                    continue

        cart_items = [item for item in cart_items if item['cart_id'] not in to_remove_ids]
        for item in cart_items:
            if item['cart_id'] in update_quantities:
                item['quantity'] = update_quantities[item['cart_id']]

        save_cart(cart_items)

    cart_display = prepare_cart_items_with_books(cart_items)
    total_amount = calculate_cart_total(cart_display)

    return render_template('cart.html', cart_items=cart_display, total_amount=total_amount)

@app.route('/checkout', methods=['GET', 'DELETE', 'POST'])
def checkout_page():
    cart_items = read_cart()
    cart_display = prepare_cart_items_with_books(cart_items)

    statusfilter = 'All'  # as a placeholder
    orderitems = []
    ratingfilter = 'All'  # all ratings filter

    if request.method == 'DELETE':
        # Spec unclear on exact purpose, so just return empty response
        return ('', 204)

    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or not payment_method:
            # Invalid submission, just re-render
            return render_template('checkout.html', cart_items=cart_display, statusfilter=statusfilter, orderitems=orderitems, ratingfilter=ratingfilter)

        orders = read_orders()
        orderitems_all = read_order_items()

        new_order_id = get_next_id(orders, 'order_id')
        today = datetime.today().strftime('%Y-%m-%d')
        total_amount = calculate_cart_total(cart_display)

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }

        orders.append(new_order)
        save_orders(orders)

        current_order_item_id = get_next_id(orderitems_all, 'order_item_id')
        for item in cart_items:
            order_item = {
                'order_item_id': current_order_item_id,
                'order_id': new_order_id,
                'book_id': item['book_id'],
                'quantity': item['quantity'],
                'price': item['quantity'] * next((b['price'] for b in read_books() if b['book_id']==item['book_id']), 0)
            }
            orderitems_all.append(order_item)
            current_order_item_id += 1

        save_order_items(orderitems_all)

        # Do not clear cart.txt according to spec

        return redirect(url_for('order_history_page'))

    # GET method
    return render_template('checkout.html', cart_items=cart_display, statusfilter=statusfilter, orderitems=orderitems, ratingfilter=ratingfilter)

