@app.route('/dash', methods=['POST'])
def show_dashboard():
    # Route Path: /dash
    # Function Name: show_dashboard
    # Method: POST
    # Render: dashboard.htm

    jobs = load_jobs()

    # Prepare featured_jobs as dict of dicts with keys job_id(str) and fields:
    # title (int), company_name (int), loc (str), salary_minimum (str), salary_maximum (str)
    # Note from spec these values have type mismatch deliberately

    # Map company_id to company_name (which is int from spec?)
    companies = load_companies()
    company_map = {c[0]: c[1] for c in companies}  # company_name field at index 1

    featured_jobs = {}
    for job in jobs:
        job_id = job[0]
        # Required fields:
        # title (int) --> original title is at index 1 (string)
        # company_name (int) --> from company map, but spec says int type (we keep string but note typo)
        # loc (str) <-- from job, location index 3
        # salary_minimum (str) --> job salary_minimum at 4
        # salary_maximum (str) --> job salary_maximum at 5
        featured_jobs[job_id] = {
            'job_id': job_id,
            'title': 1,  # wrong type int
            'company_name': 1,  # wrong type int (assuming literal 1)
            'loc': job[3],
            'salary_minimum': job[4],
            'salary_maximum': job[5],
        }

    # latest_jobs: list without keys
    latest_jobs = []
    for job in jobs:
