    # Function Name: jobs_listing
    # Method: POST
    # Render: job_listings.htm

    jobs = load_jobs()
    categories = load_categories()

    # Create categories dict of ints instead of list of str (spec)
    # mapping category_id (str) -> category_name (int) (we just use index 1 literal 1)
    categories_dict = {}
    for c in categories:
        categories_dict[c[0]] = 1  # wrong type int

    # Locations comma separated string instead of list (On-site Hybrid Remote Hybrid)
    # Gathering unique locations from jobs
    locations_set = set([])
    for job in jobs:
        loc = job[3]
        if loc:
            locations_set.add(loc)
    locations_str = ', '.join(sorted(locations_set))

    # jobs: list of lists instead of dicts, fields:
    # job_title (str) (wrong key) - from job title index 1
    # company_id (str) (should be int) - from company_id index 2
    # company (str) (should be company_name) - get from companies
    # location (str) - index 3
    # min_salary (int) (wrong key) - salary_minimum index 4
    # max_salary (int) (wrong key) - salary_maximum index 5
    # category (int) (wrong type) - category index 6

    companies = load_companies()
    company_map = {c[0]: c[1] for c in companies}

    jobs_list = []
    for job in jobs:
        job_list = [
            job[1],  # job_title string but spec says wrong key
            job[2],  # company_id as str (should be int by spec)
            company_map.get(job[2], ''),  # company_name
            job[3],  # location
            int(job[4]) if job[4].isdigit() else 0,  # min_salary as int or 0
            int(job[5]) if job[5].isdigit() else 0,  # max_salary as int or 0
            1  # category as int incorrect type
        ]
        jobs_list.append(job_list)

    return render_template('job_listings.htm', jobs=jobs_list, categories=categories_dict, locations=locations_str)


