# Utility functions to load files

def load_users():
    users = {}
    path = os.path.join('data', 'users.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, fullname = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'fullname': fullname
                    }
    return users


def load_menu():
    menu = []
    path = os.path.join('data', 'menu.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    try:
                        dishid = int(parts[0])
                        name = parts[1]
                        category = parts[2]
                        price = parts[3]
                        description = parts[4]
                        ingredients = [i.strip() for i in parts[5].split(',')] if parts[5] else []
                        dietary = parts[6]
                        avg_rating = float(parts[7])
                        menu.append({
                            'dishid': dishid,
                            'name': name,
                            'category': category,
                            'price': price,
                            'description': description,
                            'ingredients': ingredients,
                            'dietary': dietary,
                            'avg_rating': avg_rating
                        })
                    except Exception:
                        continue
    return menu


